INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1001, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 0, 0, 0, "春咲 ひより", "お！\nあそこに困ってそうな人発見！", 1, 1, 2, 0, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1002, "わ、わたし、\nなに言ってるんだろ\nあはは…", 0, 0, 0, "草野 優衣", "大切な人を\n守れるようになりたい…って", 1, 1, 2, 0, "みんなみたいに\nわたしも強くならなきゃ", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1003, "少しは磨かれると思いますよ。", 0, 0, 0, "士条 怜", "キミに必要な集中力と感性が", 1, 1, 2, 0, "フェンシングを始めてみては？", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.5, 1004, "みそぎはねぇ、\nかくれんぼやりたい！", 0, 0, 0, "穂高 みそぎ", "今日はなにして遊ぶ？", 1, 1, 2, 0, "ねぇ、にいちゃん！", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1006, "私といっしょに…\nいかない？", 0, 0, 0, "風宮 あかり", "ねぇ…", 1, 1, 2, 0, "風宮あかりです", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.5, 1007, "食べ物の恨みは怖いのー", 0, 0, 0, "出雲 宮子", "プリンたべたいのー", 1, 1, 2, 0, "出雲宮子なのー", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1008, "いいよ。\n見られることは運命さ…", 0, 0, 0, "虹村 雪", "キミもボクの美貌に\n吸い寄せられたんだね。", 1, 1, 2, 0, "ボクは虹村雪。", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1009, "人呼んで「疾風の冥姫」!!", 0, 0, 0, "柊杏奈", "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 1, 1, 2, 0, "フッ…聞いて後悔するがいい！", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.5, 1010, "ほんまおおきにやわ～♪", 0, 0, 0, "姫宮 真歩", "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 1, 1, 2, 0, "マホマホ王国のプリンセス、\nまほ姫どす", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1011, "ここで会ったが\n100年目～！", 0, 0, 0, "衣之咲 璃乃", "生き別れたお兄ちゃんを探して\n三千世界！", 1, 1, 2, 0, "衣之咲璃乃です！", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1012, "…って、お願い！\n誰にも言わないでおいて～！", 0, 0, 0, "柏崎 初音", "ち、超能力って…\n何のことかな～？", 1, 1, 2, 0, "私はハツネ、\n結構強いんだよ。\nきらーん☆", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1016, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 0, 0, 0, "美波 鈴奈", "一応カリスマ読モJKやってまっす！", 1, 1, 2, 0, "ちょす！\n美波鈴奈だよ～♪", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1017, "でも、沖縄もとってもいいとこさー", 0, 0, 0, "喜屋武 香織", "東京は遊園地みたいなところさー", 1, 1, 2, 0, "はいたーい。\n喜屋武香織さー。", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1018, "イオちゃんって呼んでね。", 0, 0, 0, "支倉 伊緒", "先生って呼ばれるのは\nくすぐったいから", 1, 1, 2, 0, "支倉伊緒です。", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.5, 1020, "ミミをおいてかないでぇ～", 0, 0, 0, "茜 ミミ", "あ！/\お兄ちゃ～ん\nまってよ～", 1, 1, 2, 0, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.5, 1021, "ふぇぇぇぇぇん……", 0, 0, 0, "栗林 くるみ", "あの……\nふぇ……", 1, 1, 2, 0, "あ…あの…えっと…\n栗…林…くるみ…です……", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1022, "なんてありがとうございます！", 0, 0, 0, "風宮 より", "こんな私に貴重な時間を\n割いていただき、", 1, 1, 2, 0, "風宮よりです。\nあああああ！", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.5, 1023, "私こっち行きたいー\nね、早く早くー", 0, 0, 0, "北条 綾音", "おにいちゃんどこいくの？\nえ？", 1, 1, 2, 0, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1025, "これて何か違う…\nあああすみません！", 0, 0, 0, "天野 すずめ", "ふ、不束者ですが\nどうぞ末永く…って、", 1, 1, 2, 0, "わっ…わっ…私、\n天野すずめといいます！", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1027, "離しませんわ………\n絶対に…!!", 0, 0, 0, "倉石 恵理子", "あなたは…運命の……\n伴侶……", 1, 1, 2, 0, "……クスクス…私は\n…倉石恵理子……", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1028, "…そうでしょ？？", 0, 0, 0, "佐々木 咲恋", "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 1, 1, 2, 0, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1029, "あはは、\n私もまだまだだなぁ～", 0, 0, 0, "桜井 望", "ぇっと…\nキミ、私のこと知らないの?!", 1, 1, 2, 0, "桜井望だよ！\nよろしくねっ", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1030, "ショーグン、\nワタシと一緒に天下統一デース！", 0, 0, 0, "ニノン・ジュベール", "初めまして、\n私はニノン・ジュベール申すデス！", 1, 1, 2, 0, "デケデケデンっ！", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1031, "おかしいですね……", 0, 0, 0, "上喜 しのぶ", "でもって私の隣にいるのが……\nえ、見えない？", 1, 1, 2, 0, "上喜しのぶです。\n手元のドクロが父です。", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.5, 1033, "そう、\nオラのボケに突っ込める相方が…！", 0, 0, 0, "野戸まひる", "けんども\nそれには足りないモンが…", 1, 1, 2, 0, "目指すはビッグな\nお笑い芸人だっぺ！", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1034, "ちょ\nちょっと一杯飲んできます…！", 0, 0, 0, "綾瀬 ゆかり", "ちょっと緊張しちゃって…", 1, 1, 2, 0, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.5, 1036, "これ以上お話しすることは…\nないです！", 0, 0, 0, "氷川 鏡華", "知らない人とは話しちゃいけないので", 1, 1, 2, 0, "氷川鏡華…です", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1038, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 0, 0, 0, "柏崎 栞", "……あ、アラーム。", 1, 1, 2, 0, "柏崎…栞です。", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1040, "野に咲く花が、\n唯一の話相手です。", 0, 0, 0, "双葉 碧", "私、一人も友達がいなくて……", 1, 1, 2, 0, "ふ、双葉碧です。", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1042, "そう思っています。", 0, 0, 0, "三角 千歌", "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 1, 1, 2, 0, "三角千歌です。", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1043, "う、疑ってすまなかったな…", 0, 0, 0, "安芸 真琴", "あぁ？\nお前のそいつの仲間か？", 1, 1, 2, 0, "安芸真琴だ。", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1044, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 0, 0, 0, "イリヤ・オーンスタイン", "生けとし生ける全ての者よ！", 1, 1, 2, 0, "わらわこそは夜を総べる者！", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1045, "ｌク、クウカに何かご用ですか!?", 0, 0, 0, "遠見 空花", "ぐふふふふ……はっ！", 1, 1, 2, 0, "そこで騎士は妖精を乱暴に……", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1046, "う～ん…\n猫ってホントに最高にゃ～♪", 0, 0, 0, "宮坂たまき", "自由気ままで♪\n寝て遊んで、食べてケンカして…", 1, 1, 2, 0, "宮坂たまきにゃ♪\n猫はいいにゃよ？", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1048, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 0, 0, 0, "大神 美冬", "それでは早速クエストに…", 1, 1, 2, 0, "大神美冬よ！", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1049, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 0, 0, 0, "星野静流", "クエストもバトルも\n掃除も洗濯も", 1, 1, 2, 0, "星野静流だよ！", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.5, 1050, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 0, 0, 0, "玉泉美咲", "見ての通りの\nセクシー美少女で", 1, 1, 2, 0, "アタシは玉泉美咲。", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.4, 1052, "？？？？", 0, 0, 0, "リマ", "？？？？", 1, 1, 2, 0, "？？？", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.5, 1053, "そ、そこまでいうなら\nもらってやる", 0, 0, 0, "モニカ・ヴァイスヴィント", "菓子でつろうなどと\n稚拙な策を……", 1, 1, 2, 0, "モニカ・ヴァイスヴィントだ。", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.5, 1058, "そ、そこまでいうなら\nもらってやる", 0, 0, 0, "ペコリーヌ", "菓子でつろうなどと\n稚拙な策を……", 1, 1, 2, 0, "モニカ・ヴァイスヴィントだ。", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.5, 1059, "そ、そこまでいうなら\nもらってやる", 0, 0, 0, "コッコロ", "菓子でつろうなどと\n稚拙な策を……", 1, 1, 2, 0, "モニカ・ヴァイスヴィントだ。", 0);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (1, 1.5, 1060, "そ、そこまでいうなら\nもらってやる", 0, 0, 0, "キャル", "菓子でつろうなどと\n稚拙な策を……", 1, 1, 2, 0, "モニカ・ヴァイスヴィントだ。", 0);
